// Get the structured resume data from Parse Analysis JSON node
const parsedData = $('Parse Analysis JSON1').item.json;
const resumeData = parsedData.improved_resume;

// Get photo data from Prepare the Photo node
let photoHTML = '';
try {
  const photoData = $('Prepare the Photo1').first().json;
  if (photoData.has_photo && photoData.photo_base64) {
    photoHTML = `
      <div style="text-align: center; margin-bottom: 25px; margin-top: 0;">
        <img src="data:image/jpeg;base64,${photoData.photo_base64}" 
             style="width: 110px; height: 110px; border-radius: 50%; object-fit: cover; border: 4px solid white; box-shadow: 0 3px 6px rgba(0,0,0,0.3);" 
             alt="Profile Photo">
      </div>
    `;
  }
} catch (e) {
  console.log('No photo available');
}

// Get webhook data
const webhookData = $('Webhook1').item.json.body;

// Build the HTML with icons and ONE PAGE layout
const html = `
<!DOCTYPE html>
<html>
<head>
  <meta charset="UTF-8">
  <style>
    * {
      margin: 0;
      padding: 0;
      box-sizing: border-box;
    }

    @page {
      size: A4;
      margin: 0;
    }

    body {
      font-family: 'Segoe UI', 'Calibri', Arial, sans-serif;
      font-size: 9pt;
      line-height: 1.4;
      color: #333;
    }

    .container {
      display: flex;
      height: 297mm;
      max-height: 297mm;
      overflow: hidden;
    }

    /* LEFT SIDEBAR - DARK BLUE */
    .sidebar {
      width: 32%;
      background: linear-gradient(135deg, #1e3a5f 0%, #2c5282 100%);
      padding: 25px 18px;
      color: white;
    }

    .sidebar h2 {
      font-size: 10pt;
      font-weight: 700;
      color: white;
      text-transform: uppercase;
      letter-spacing: 2px;
      margin: 20px 0 10px 0;
      padding-bottom: 6px;
      border-bottom: 2px solid white;
    }

    .sidebar h2:first-of-type {
      margin-top: 0;
    }

    .sidebar p {
      font-size: 8pt;
      line-height: 1.5;
      margin: 5px 0;
      color: #e8f0f7;
      padding-left: 20px;
      position: relative;
    }

    .sidebar p.with-icon::before {
      position: absolute;
      left: 0;
      font-size: 10pt;
    }

    .sidebar p.phone::before {
      content: "📞";
    }

    .sidebar p.email::before {
      content: "✉️";
    }

    .sidebar p.location::before {
      content: "📍";
    }

    .sidebar p.linkedin::before {
      content: "🔗";
    }

    .sidebar ul {
      list-style: none;
      padding: 0;
    }

    .sidebar li {
      font-size: 8pt;
      line-height: 1.5;
      margin: 5px 0;
      color: #e8f0f7;
      padding-left: 0;
    }

    .sidebar strong {
      font-weight: 700;
      color: white;
      display: block;
      margin-top: 10px;
      margin-bottom: 4px;
      font-size: 8.5pt;
    }

    .sidebar a {
      color: #a8d0f0;
      text-decoration: none;
      word-break: break-all;
      font-size: 7.5pt;
    }

    /* RIGHT MAIN CONTENT */
    .main-content {
      width: 68%;
      padding: 25px 30px;
      background: white;
    }

    .header {
      margin-bottom: 18px;
      padding-bottom: 10px;
      border-bottom: 3px solid #1e3a5f;
    }

    .name {
      font-size: 24pt;
      font-weight: 700;
      color: #1e3a5f;
      text-transform: uppercase;
      letter-spacing: 3px;
      margin-bottom: 3px;
    }

    .job-title {
      font-size: 10pt;
      font-weight: 600;
      color: #666;
      text-transform: uppercase;
      letter-spacing: 1.5px;
    }

    .main-content h2 {
      font-size: 11pt;
      font-weight: 700;
      color: #1e3a5f;
      text-transform: uppercase;
      letter-spacing: 2px;
      margin: 15px 0 10px 0;
      padding-bottom: 5px;
      border-bottom: 2px solid #1e3a5f;
      position: relative;
      padding-left: 25px;
    }

    .main-content h2::before {
      position: absolute;
      left: 0;
      font-size: 13pt;
    }

    .main-content h2.profile::before {
      content: "👤";
    }

    .main-content h2.experience::before {
      content: "💼";
    }

    .main-content h2.education::before {
      content: "🎓";
    }

    .main-content h2.projects::before {
      content: "🚀";
    }

    .main-content h3 {
      font-size: 10pt;
      font-weight: 700;
      color: #1e3a5f;
      margin-top: 10px;
      margin-bottom: 2px;
    }

    .main-content h4 {
      font-size: 9pt;
      font-weight: 600;
      color: #2c5282;
      margin-top: 8px;
      margin-bottom: 2px;
    }

    .date-range {
      font-size: 8pt;
      color: #888;
      text-transform: uppercase;
      font-weight: 600;
      margin-bottom: 3px;
      float: right;
      font-style: italic;
    }

    .company {
      font-size: 9pt;
      color: #666;
      font-style: italic;
      margin-bottom: 6px;
    }

    .main-content p {
      font-size: 9pt;
      line-height: 1.5;
      margin: 6px 0;
      text-align: justify;
      color: #444;
    }

    .main-content ul {
      margin: 5px 0 10px 18px;
      padding: 0;
    }

    .main-content li {
      font-size: 8.5pt;
      line-height: 1.5;
      margin: 3px 0;
      color: #444;
    }

    .section {
      margin-bottom: 15px;
      clear: both;
    }

    .experience-item {
      margin-bottom: 12px;
      position: relative;
    }
  </style>
</head>
<body>
  <div class="container">
    <!-- LEFT SIDEBAR -->
    <div class="sidebar">
      ${photoHTML}

      <h2>CONTACT</h2>
      ${resumeData.contact.phone ? `<p class="with-icon phone">${resumeData.contact.phone}</p>` : ''}
      <p class="with-icon email">${resumeData.contact.email}</p>
      ${resumeData.contact.location ? `<p class="with-icon location">${resumeData.contact.location}</p>` : ''}
      ${resumeData.contact.linkedin ? `<p class="with-icon linkedin"><a href="${resumeData.contact.linkedin}">${resumeData.contact.linkedin.replace('https://', '').replace('http://', '')}</a></p>` : ''}

      <h2>SKILLS</h2>
      ${resumeData.skills.technical && resumeData.skills.technical.length > 0 ? `
        <strong>Technical Skills:</strong>
        <p>${resumeData.skills.technical.join(', ')}</p>
      ` : ''}

      ${resumeData.skills.tools && resumeData.skills.tools.length > 0 ? `
        <strong>Tools & Technologies:</strong>
        <p>${resumeData.skills.tools.join(', ')}</p>
      ` : ''}

      ${resumeData.skills.soft_skills && resumeData.skills.soft_skills.length > 0 ? `
        <strong>Soft Skills:</strong>
        <p>${resumeData.skills.soft_skills.join(', ')}</p>
      ` : ''}

      ${resumeData.certifications && resumeData.certifications.length > 0 ? `
        <h2>CERTIFICATIONS</h2>
        <ul>
          ${resumeData.certifications.slice(0, 6).map(cert => `<li>• ${cert}</li>`).join('')}
        </ul>
      ` : ''}

      <h2>LANGUAGES</h2>
      <p>• English (Fluent)</p>
      <p>• Hindi (Native)</p>
      <p>• Marathi (Native)</p>
    </div>

    <!-- RIGHT MAIN CONTENT -->
    <div class="main-content">
      <div class="header">
        <div class="name">${resumeData.contact.name.toUpperCase()}</div>
        <div class="job-title">${webhookData.job_role ? webhookData.job_role.toUpperCase() : 'PROFESSIONAL'}</div>
      </div>

      <div class="section">
        <h2 class="profile">PROFILE</h2>
        <p>${resumeData.summary}</p>
      </div>

      ${resumeData.experience && resumeData.experience.length > 0 ? `
        <div class="section">
          <h2 class="experience">WORK EXPERIENCE</h2>
          ${resumeData.experience.slice(0, 2).map(exp => `
            <div class="experience-item">
              <div class="date-range">${exp.duration.toUpperCase()}</div>
              <h3>${exp.title}</h3>
              <div class="company">${exp.company}</div>
              <ul>
                ${exp.achievements.slice(0, 3).map(ach => `<li>${ach}</li>`).join('')}
              </ul>
            </div>
          `).join('')}
        </div>
      ` : ''}

      ${resumeData.education && resumeData.education.length > 0 ? `
        <div class="section">
          <h2 class="education">EDUCATION</h2>
          ${resumeData.education.slice(0, 2).map(edu => `
            <div style="margin-bottom: 10px;">
              <div class="date-range">${edu.year}</div>
              <h3>${edu.degree}</h3>
              <div class="company">${edu.institution}</div>
              ${edu.details ? `<p style="font-size: 8.5pt;">${edu.details}</p>` : ''}
            </div>
          `).join('')}
        </div>
      ` : ''}

      ${resumeData.projects && resumeData.projects.length > 0 ? `
        <div class="section">
          <h2 class="projects">PROJECTS</h2>
          ${resumeData.projects.slice(0, 3).map(proj => `
            <div style="margin-bottom: 10px;">
              <h4>${proj.name}</h4>
              <p style="font-size: 8.5pt;">${proj.description}</p>
              ${proj.technologies && proj.technologies.length > 0 ? `<p style="font-size: 8pt;"><strong>Tech:</strong> ${proj.technologies.join(', ')}</p>` : ''}
            </div>
          `).join('')}
        </div>
      ` : ''}
    </div>
  </div>
</body>
</html>
`;

return [{
  json: {
    html_content: html,
    markdown_resume: html,
    analysis: parsedData.analysis,
    improved_resume: resumeData,
    email: webhookData.user_email,
    job_role: webhookData.job_role,
    company_name: webhookData.company_name
  }
}];

// Get all input items
const items = $input.all();

if (!items || items.length === 0) {
  throw new Error('No input data received from OpenAI');
}

const item = items[0].json;

// Get the response content from OpenAI
let responseContent;

if (item.content) {
  responseContent = item.content;
} else if (item.choices && item.choices.length > 0) {
  responseContent = item.choices[0].message.content;
} else if (item.message && item.message.content) {
  responseContent = item.message.content;
} else {
  throw new Error('Unexpected OpenAI response format');
}

console.log('=== RAW OPENAI RESPONSE ===');
console.log('Response length:', responseContent.length);
console.log('First 500 chars:', responseContent.substring(0, 500));
console.log('Last 500 chars:', responseContent.substring(Math.max(0, responseContent.length - 500)));

// Clean the response aggressively
let cleanResponse = responseContent.trim();

// Remove markdown code blocks
cleanResponse = cleanResponse.replace(/```json\s*/gi, '');
cleanResponse = cleanResponse.replace(/```\s*/g, '');

// Remove any text before first {
const firstBrace = cleanResponse.indexOf('{');
if (firstBrace !== -1) {
  cleanResponse = cleanResponse.substring(firstBrace);
}

// Remove any text after last }
const lastBrace = cleanResponse.lastIndexOf('}');
if (lastBrace !== -1) {
  cleanResponse = cleanResponse.substring(0, lastBrace + 1);
}

// Fix common JSON issues
cleanResponse = cleanResponse
  .replace(/,(\s*[}\]])/g, '$1')  // Remove trailing commas
  .replace(/\n/g, ' ')  // Remove newlines
  .replace(/\r/g, '')  // Remove carriage returns
  .replace(/\t/g, ' ')  // Replace tabs with spaces
  .replace(/\s+/g, ' ')  // Collapse multiple spaces
  .trim();

console.log('=== CLEANED RESPONSE ===');
console.log('Cleaned length:', cleanResponse.length);
console.log('First 300 chars:', cleanResponse.substring(0, 300));

// Try to parse
let parsedData;
try {
  parsedData = JSON.parse(cleanResponse);
  console.log('✅ JSON parsed successfully');
} catch (parseError) {
  console.error('❌ JSON parse failed:', parseError.message);
  console.error('Failed at position:', parseError.message.match(/position (\d+)/)?.[1]);

  // Try to find the problematic area
  const errorPos = parseInt(parseError.message.match(/position (\d+)/)?.[1] || '0');
  const contextStart = Math.max(0, errorPos - 100);
  const contextEnd = Math.min(cleanResponse.length, errorPos + 100);
  console.error('Context around error:', cleanResponse.substring(contextStart, contextEnd));

  // Last resort: try to extract JSON objects manually
  try {
    // Find analysis and improved_resume sections separately
    const analysisMatch = cleanResponse.match(/"analysis"\s*:\s*\{[^}]+\}/);
    const improvedResumeMatch = cleanResponse.match(/"improved_resume"\s*:\s*\{[\s\S]+\}/);

    if (analysisMatch && improvedResumeMatch) {
      const reconstructed = `{${analysisMatch[0]},${improvedResumeMatch[0]}}`;
      parsedData = JSON.parse(reconstructed);
      console.log('⚠️ JSON reconstructed from parts');
    } else {
      throw new Error('Could not reconstruct valid JSON. Raw response: ' + cleanResponse.substring(0, 1000));
    }
  } catch (reconstructError) {
    throw new Error('Failed to parse JSON after all attempts. Original error: ' + parseError.message + '. Response preview: ' + cleanResponse.substring(0, 500));
  }
}

// Validate structure
if (!parsedData.analysis) {
  throw new Error('Parsed JSON is missing "analysis" field');
}

if (!parsedData.improved_resume) {
  throw new Error('Parsed JSON is missing "improved_resume" field');
}

if (!parsedData.improved_resume.contact) {
  throw new Error('Parsed JSON is missing "improved_resume.contact" field');
}

console.log('✅ JSON validation passed');
console.log('Analysis score:', parsedData.analysis.alignment_score);
console.log('Candidate name:', parsedData.improved_resume.contact.name);

// Return both analysis and improved resume
return [{ json: parsedData }];

