// Validate extracted PDF text quality
const item = $input.first();

let extractedText = '';

// Get the extracted text
if (item.json && item.json.text) {
  extractedText = item.json.text;
} else if (item.json && item.json.data) {
  extractedText = item.json.data;
}

// Clean and check the text
const cleanText = extractedText.trim();

console.log('=== PDF TEXT VALIDATION ===');
console.log('Extracted length:', cleanText.length);
console.log('First 200 chars:', cleanText.substring(0, 200));

// Validation checks
const validationErrors = [];

// Check 1: Minimum length
if (cleanText.length < 100) {
  validationErrors.push('Extracted text is too short (less than 100 characters)');
}

// Check 2: Check for actual words (not just garbage characters)
const words = cleanText.match(/[a-zA-Z]{3,}/g) || [];
if (words.length < 20) {
  validationErrors.push('PDF contains too few readable words');
}

// Check 3: Check if it's mostly special characters/numbers (sign of image PDF)
const alphaChars = (cleanText.match(/[a-zA-Z]/g) || []).length;
const totalChars = cleanText.length;
const alphaRatio = alphaChars / totalChars;

if (alphaRatio < 0.5) {
  validationErrors.push('PDF appears to be image-based or contains mostly non-text content');
}

// Check 4: Look for common resume keywords
const resumeKeywords = ['experience', 'education', 'skills', 'work', 'university', 'college', 'project', 'name', 'email', 'phone'];
const foundKeywords = resumeKeywords.filter(keyword => 
  cleanText.toLowerCase().includes(keyword)
);

if (foundKeywords.length < 2) {
  validationErrors.push('PDF does not appear to contain resume content');
}

// If validation failed, return error
if (validationErrors.length > 0) {
  console.error('PDF validation failed:', validationErrors);

  return [{
    json: {
      validation_failed: true,
      errors: validationErrors,
      extracted_length: cleanText.length,
      words_found: words.length,
      alpha_ratio: alphaRatio,
      error_response: {
        status: "error",
        message: "Your PDF could not be processed properly.",
        issue: "The PDF appears to be image-based (scanned) or does not contain extractable text.",
        requirements: [
          "PDF must contain selectable/copyable text (not scanned images)",
          "Test your PDF: Open it and try to select/copy text with your cursor",
          "If you cannot copy text from the PDF, it won't work with our system"
        ],
        how_to_fix: {
          "if_scanned": "Use OCR software to convert your scanned PDF to text-based PDF (Adobe Acrobat, smallpdf.com, or Google Drive)",
          "if_image": "Recreate your resume as a proper text-based PDF (not a screenshot)",
          "if_word_doc": "Export from Word using File → Save As → PDF (ensure text is selectable)"
        },
        technical_details: validationErrors,
        tip: "A good text-based PDF will let you highlight and copy text. Try it before uploading!"
      }
    }
  }];
}

// Validation passed - return the text
console.log('✅ PDF validation passed');
console.log('Words found:', words.length);
console.log('Keywords found:', foundKeywords);

return [{
  json: {
    text: cleanText,
    validation_passed: true,
    words_count: words.length,
    keywords_found: foundKeywords,
    quality: 'good'
  },
  binary: item.binary
}];

